#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXA 1000000
int freq[MAXA + 1];
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *used = (int*)malloc(N * sizeof(int));
        int usedCnt = 0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            if(freq[x]==0) used[usedCnt++] = x;
            freq[x]++;
        }
        long long ans = 1;
        for(int i=0;i<usedCnt;i++){
            int v = used[i];
            ans = ans * (freq[v] + 1) % MOD;
            freq[v] = 0; // reset for next test case
        }
        ans = (ans - 1 + MOD) % MOD;
        printf("%lld\n", ans);
        free(used);
    }
    return 0;
}

