#include <bits/stdc++.h>
using namespace std;
const long long MOD = 1000000007LL;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    const int MAXA = 1000000;
    static int freq[MAXA+1];
    while(T--){
        int N; cin>>N;
        vector<int> used; used.reserve(N);
        for(int i=0;i<N;i++){
            int x; cin>>x;
            if(freq[x]==0) used.push_back(x);
            ++freq[x];
        }
        long long ans = 1;
        for(int v: used){
            ans = ans * (freq[v] + 1) % MOD;
            freq[v]=0;
        }
        ans = (ans - 1 + MOD) % MOD;
        cout<<ans<<"\n";
    }
    return 0;
}

