import sys
MOD = 1000000007

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        freq = {}
        for _ in range(N):
            x = int(next(it))
            freq[x] = freq.get(x, 0) + 1
        ans = 1
        for cnt in freq.values():
            ans = ans * (cnt + 1) % MOD
        ans = (ans - 1) % MOD
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

